mapper.select:
SELECT m.CallBackKey, m.RegDate, m.RegTime, m.ReqNum, m.ReqNm, m.AgentID, m.AgentNm, m.CallYn AS MstCallYn, m.CallRet AS MstCallRet, m.DelYn AS MstDelYn, CONVERT(VARCHAR, m.CreationTime, 120) AS MstCreationTime, m.Creator AS MstCreator, CONVERT(VARCHAR, m.LastUpdated, 120) AS MstLastUpdated, m.LastUser AS MstLastUser, d.Seq, d.CallYn AS DtlCallYn, d.CallRet AS DtlCallRet, CASE WHEN d.CallRet = '01' THEN '통화성공' WHEN d.CallRet = '02' THEN '통화실패' WHEN d.CallRet = '03' THEN '콜백포기' ELSE '기타' END AS DtlCallRetNm, d.Memo, d.DelYn AS DtlDelYn, d.VoiceFile, CONVERT(VARCHAR, d.CreationTime , 120) AS DtlCreationTime, d.Creator AS DtlCreator, CONVERT(VARCHAR, d.LastUpdated , 120) AS DtlLastUpdated, d.LastUser AS DtlLastUser, (SELECT COUNT(*) FROM XBOLTDLM.CALLBACK_DTL WHERE CallBackKey = #{CallBackKey} AND CallRet IN ('02', '03')) AS RejectCount FROM XBOLTDLM.CALLBACK_MST m JOIN XBOLTDLM.CALLBACK_DTL d ON m.CallBackKey = d.CallBackKey WHERE d.CallBackKey = #{CallBackKey} AND m.AgentID = #{AgentID} AND d.Seq =
#{varSeq}
(SELECT MAX(Seq) FROM XBOLTDLM.CALLBACK_DTL WHERE CallBackKey = #{CallBackKey})

SELECT MAX(seq) AS makeSeq
  FROM XBOLTDLM.CALLBACK_DTL
 WHERE CallBackKey = #{CallBackKey};

mapper.update:
UPDATE XBOLTDLM.CALLBACK_DTL	
SET CallYn = #{CallYn},  
    CallRet = #{CallRet},  
    Memo = #{Memo},
    DelYn = 'N',
    LastUpdated = GETDATE(),	
    LastUser = #{LastUser}
WHERE CallBackKey = #{CallBackKey}
  AND Seq = #{reqSeq};

UPDATE XBOLTDLM.CALLBACK_MST		
SET CallYn = 'Y', 	
    CallRet = '01',  	
    LastUpdated = GETDATE(),		
    LastUser = #{LastUser}
WHERE CallBackKey = #{CallBackKey};

UPDATE XBOLTDLM.CALLBACK_MST
SET AgentID = #{NewAgentID},  
	AgentNm = #{NewAgentName},
    LastUpdated = GETDATE(), 
    LastUser = #{LastUser}    
WHERE CallBackKey = #{CallBackKey};
